import chess

class ChessEvaluator:
    def __init__(self, board):
        self.board = board

    def evaluate_position(self):
        evaluation = 0
        for i in range(8):
            for j in range(8):
                piece = self.board.piece_at(i*8 + j)
                if piece:
                    if piece.color == chess.WHITE:
                        if piece.piece_type == chess.PAWN:
                            evaluation += 1
                        elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                            evaluation += 3
                        elif piece.piece_type == chess.ROOK:
                            evaluation += 5
                        elif piece.piece_type == chess.QUEEN:
                            evaluation += 9
                    else:
                        if piece.piece_type == chess.PAWN:
                            evaluation -= 1
                        elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                            evaluation -= 3
                        elif piece.piece_type == chess.ROOK:
                            evaluation -= 5
                        elif piece.piece_type == chess.QUEEN:
                            evaluation -= 9
        return evaluation

    def controlled_squares(self):
        white_controlled = 0
        black_controlled = 0
        for i in range(8):
            for j in range(8):
                for move in chess.SQUARES:
                    if chess.square(i, j) == move:
                        if self.board.is_attacked_by(chess.WHITE, move):
                            white_controlled += 1
                        if self.board.is_attacked_by(chess.BLACK, move):
                            black_controlled += 1
        return white_controlled, black_controlled

    def active_moves(self):
        white_moves = 0
        black_moves = 0
        for move in self.board.legal_moves:
            if move.from_square % 8 <= 3 and move.to_square % 8 <= 3:
                white_moves += 1
            else:
                black_moves += 1
        return white_moves, black_moves

    def check_and_mate_chances(self):
        white_check = 0
        black_check = 0
        if self.board.is_check():
            if self.board.turn == chess.WHITE:
                white_check += 1
            else:
                black_check += 1
        if self.board.is_checkmate():
            if self.board.turn == chess.WHITE:
                black_check += 100
            else:
                white_check += 100
        return white_check, black_check

    def evaluate(self):
        material = self.evaluate_position()
        white_controlled, black_controlled = self.controlled_squares()
        white_moves, black_moves = self.active_moves()
        white_check, black_check = self.check_and_mate_chances()
        evaluation = material + (white_controlled - black_controlled) / 10 + (white_moves - black_moves) / 10 + white_check - black_check
        return evaluation

